import Foundation

enum NetworkError: Error {
    case invalidURL
    case noData
    case decodingError(Error)
    case apiError(String)
    case unknownError(Error)
}

enum HTTPMethod: String {
    case get = "GET"
    case post = "POST"
}

struct APIConstants {
    enum Environment: String {
        case development = "dev"
        case staging = "stg"
        case production = "prod"
    }

    // You would typically set this in a build configuration (e.g., User-Defined Setting)
    // and access it via Bundle.main.infoDictionary
