    static var baseURL: URL {
        switch currentEnvironment {
        case .development:
            return URL(string: "https://dev.api.example.com")!
        case .staging:
            return URL(string: "https://stg.api.example.com")!
        case .production:
            return URL(string: "https://api.example.com")!
        }
    }
}

class NetworkService {
    static let shared = NetworkService()
    private let session: URLSession

    private init(session: URLSession = .shared) {
        self.session = session
    }

    func request<T: Decodable>(
        path: String,
        method: HTTPMethod,
        body: Encodable? = nil,
        headers: [String: String]? = nil,
        completion: @escaping (Result<T, NetworkError>) -> Void
    ) {
        guard let url = URL(string: path, relativeTo: APIConstants.baseURL) else {
            completion(.failure(.invalidURL))
            return
        }

        var request = URLRequest(url: url)
        request.httpMethod = method.rawValue
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")

        headers?.forEach { key, value in
            request.addValue(value, forHTTPHeaderField: key)
        }

        if let body = body {
            do {
                let jsonData = try JSONEncoder().encode(body)
                request.httpBody = jsonData
            } catch {
                completion(.failure(.decodingError(error))) // Should be encodingError but using common for simplicity
                return
            }
        }

        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(.unknownError(error)))
                return
            }

            guard let data = data else {
                completion(.failure(.noData))
                return
            }

            if let httpResponse = response as? HTTPURLResponse, !(200...299).contains(httpResponse.statusCode) {
                let errorMessage = String(data: data, encoding: .utf8) ?? "Unknown API error"
                completion(.failure(.apiError("Status code: \(httpResponse.statusCode), Message: \(errorMessage)")))
                return
            }

            do {
                let decodedObject = try JSONDecoder().decode(T.self, from: data)
                completion(.success(decodedObject))
            } catch {
                completion(.failure(.decodingError(error)))
            }
        }
        task.resume()
    }

    // MARK: - Specific API Methods (Examples)

    func authenticate(credentials: AuthRequest, completion: @escaping (Result<AuthResponse, NetworkError>) -> Void) {
        request(path: "/auth/login", method: .post, body: credentials, completion: completion)
    }

    func getUserProfile(token: String, userId: String, completion: @escaping (Result<UserProfile, NetworkError>) -> Void) {
        let headers = ["Authorization": "Bearer \(token)"]
        request(path: "/users/\(userId)/profile", method: .get, headers: headers, completion: completion)
    }

    func updateUserProfile(token: String, userId: String, profileData: UserProfileUpdate, completion: @escaping (Result<UserProfile, NetworkError>) -> Void) {
        let headers = ["Authorization": "Bearer \(token)"]
        request(path: "/users/\(userId)/profile", method: .post, body: profileData, headers: headers, completion: completion)
    }
}

